import { Link } from 'react-router-dom';import { Button } from '@/components/ui/button';import type { Supplier } from '../types';import { SupplierStatusBadge } from './SupplierStatusBadge';
export const SupplierTable=({suppliers,isLoading,onEdit,onArchive,onActivate,onSort}:{suppliers:Supplier[];isLoading:boolean;onEdit?:(s:Supplier)=>void;onArchive?:(s:Supplier)=>void;onActivate?:(s:Supplier)=>void;onSort?:(field:string)=>void})=>{
 if(isLoading)return <div className="space-y-3 p-5">{Array.from({length:6}).map((_,i)=><div key={i} className="h-14 animate-pulse rounded-lg bg-slate-100 dark:bg-slate-800"/>)}</div>;
 if(!suppliers.length)return <div className="p-12 text-center"><p className="font-semibold text-slate-700 dark:text-slate-200">No suppliers found</p><p className="mt-1 text-sm text-slate-500">Adjust the filters or create the first supplier.</p></div>;
 const heading=(label:string,field:string)=><button type="button" onClick={()=>onSort?.(field)} className="font-semibold hover:text-indigo-600">{label} ↕</button>;
 return <div className="overflow-x-auto"><table className="min-w-full text-left text-sm"><thead className="border-b border-slate-200 bg-slate-50 text-xs uppercase tracking-wider text-slate-500 dark:border-slate-700 dark:bg-slate-800/60 dark:text-slate-400"><tr><th className="px-4 py-3">{heading('Supplier','company_name')}</th><th className="px-4 py-3">Categories</th><th className="px-4 py-3">Primary Contact</th><th className="px-4 py-3">{heading('Rating','overall_rating')}</th><th className="px-4 py-3">{heading('Procurement','procurement_value')}</th><th className="px-4 py-3">Status</th><th className="px-4 py-3">Actions</th></tr></thead><tbody className="divide-y divide-slate-100 dark:divide-slate-800">{suppliers.map(s=><tr key={s.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50"><td className="px-4 py-3"><Link to={`/vendors/suppliers/${s.id}`} className="font-semibold text-indigo-600 hover:underline dark:text-indigo-400">{s.company_name}</Link><p className="font-mono text-xs text-slate-400">{s.supplier_code}</p></td><td className="max-w-48 px-4 py-3 text-slate-600 dark:text-slate-300">{s.category_names||'—'}</td><td className="px-4 py-3"><p className="text-slate-700 dark:text-slate-200">{s.contact_person||'—'}</p><p className="text-xs text-slate-400">{s.email||s.phone||''}</p></td><td className="px-4 py-3 font-semibold tabular-nums">{s.overall_rating===null?'—':`${Number(s.overall_rating).toFixed(2)} / 5`}</td><td className="px-4 py-3 tabular-nums">{s.currency} {Number(s.procurement_value).toLocaleString()}</td><td className="px-4 py-3"><SupplierStatusBadge status={s.status}/></td><td className="px-4 py-3"><div className="flex gap-1">{onEdit&&s.status!=='archived'?<Button size="sm" variant="ghost" onClick={()=>onEdit(s)}>Edit</Button>:null}{s.status==='archived'&&onActivate?<Button size="sm" variant="ghost" onClick={()=>onActivate(s)}>Activate</Button>:onArchive?<Button size="sm" variant="ghost" className="text-red-600" onClick={()=>onArchive(s)}>Archive</Button>:null}</div></td></tr>)}</tbody></table></div>;
};
